  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { ShellExec } from "./worktree-manager";
  3→import { createWorktree, removeWorktree } from "./worktree-manager";
  4→import type { AssignmentResult } from "./assignment-guard";
  5→import type { AssignmentError, OrchestratorStatus } from "./types";
  6→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  7→import { startEventBridge, type SdkMessage } from "./event-bridge";
  8→import type { StreamEvent } from "../../shared/contracts";
  9→import type { StallDetectorHandle } from "./stall-detector";
 10→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 11→import type { IntentStatus } from "../intent/types";
 12→import { log } from "../telemetry/logger";
 13→import type { SandboxAgentAdapter, SessionHandle } from "./sandbox-adapter";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types — exported for tests
 17→// ---------------------------------------------------------------------------
 18→
 19→export type SessionDeps = {
 20→  surreal: Surreal;
 21→  shellExec: ShellExec;
 22→  brainBaseUrl: string;
 23→};
 24→
 25→export type SessionErrorCode =
 26→  | "TASK_NOT_FOUND"
 27→  | "TASK_NOT_ASSIGNABLE"
 28→  | "AGENT_ALREADY_ACTIVE"
 29→  | "WORKSPACE_MISMATCH"
 30→  | "MISSING_TASK_ID"
 31→  | "WORKTREE_ERROR"
 32→  | "SESSION_NOT_FOUND"
 33→  | "SESSION_ERROR"
 34→  | "INTENT_NOT_AUTHORIZED";
 35→
 36→export type SessionError = {
 37→  code: SessionErrorCode;
 38→  message: string;
 39→  httpStatus: number;
 40→};
 41→
 42→export type SessionResult<T> =
 43→  | { ok: true; value: T }
 44→  | { ok: false; error: SessionError };
 45→
 46→export type OrchestratorSessionResult = SessionResult<{
 47→  agentSessionId: string;
 48→  streamId: string;
 49→  worktreeBranch: string;
 50→  sessionHandle?: SessionHandle;
 51→}>;
 52→
 53→export type SessionStatusResult = SessionResult<{
 54→  orchestratorStatus: OrchestratorStatus;
 55→  worktreeBranch?: string;
 56→  worktreePath?: string;
 57→  lastEventAt?: string;
 58→  startedAt?: string;
 59→  error?: string;
 60→}>;
 61→
 62→export type AbortSessionResult = SessionResult<{
 63→  aborted: boolean;
 64→  sessionId: string;
 65→}>;
 66→
 67→export type AcceptSessionResult = SessionResult<{
 68→  accepted: boolean;
 69→  sessionId: string;
 70→}>;
 71→
 72→export type ReviewResult = SessionResult<{
 73→  taskTitle: string;
 74→  diff: import("./worktree-manager").DiffResult;
 75→  session: {
 76→    orchestratorStatus: string;
 77→    worktreeBranch?: string;
 78→    startedAt?: string;
 79→    lastEventAt?: string;
 80→    toolCallCount?: number;
 81→    filesEdited?: number;
 82→  };
 83→}>;
 84→
 85→export type RejectSessionResult = SessionResult<{
 86→  rejected: boolean;
 87→  continuing: boolean;
 88→}>;
 89→
 90→export type PromptSessionResult = SessionResult<{
 91→  delivered: boolean;
 92→}>;
 93→
 94→// ---------------------------------------------------------------------------
 95→// Event iteration — port (dependencies as function signatures)
 96→// ---------------------------------------------------------------------------
 97→
 98→export type EventIterationDeps = {
 99→  emitEvent: (streamId: string, event: StreamEvent) => void;
100→  updateSessionStatus: (
101→    sessionId: string,
102→    status: OrchestratorStatus,
103→    error?: string,
104→  ) => Promise<void>;
105→  updateLastEventAt: (sessionId: string) => Promise<void>;
106→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
107→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
108→};
109→
110→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
111→  TERMINAL_ORCHESTRATOR_STATUSES,
112→);
113→
114→/**
115→ * Iterates the SDK message stream, forwarding messages through the event
116→ * bridge. Transitions session to "active" on first message, starts stall
117→ * detection, and stops on terminal status or error.
118→ *
119→ * Returns a Promise that resolves when iteration ends (for testing).
120→ * In production, this is launched fire-and-forget.
121→ */
122→export function startEventIteration(
123→  deps: EventIterationDeps,
124→  messageStream: AsyncIterable<unknown>,
125→  streamId: string,
126→  sessionId: string,
127→): Promise<void> {
128→  const stallDetector = deps.startStallDetector(sessionId, streamId);
129→
130→  const bridge = startEventBridge(
131→    {
132→      emitEvent: deps.emitEvent,
133→      updateLastEventAt: deps.updateLastEventAt,
134→    },
135→    streamId,
136→    sessionId,
137→    stallDetector,
138→  );
139→
140→  let firstMessageReceived = false;
141→  let messageCount = 0;
142→
143→  async function iterate(): Promise<void> {
144→    log.info("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
145→    try {
146→      for await (const rawMessage of messageStream) {
147→        messageCount++;
148→        const msg = rawMessage as SdkMessage;
149→        log.info("orchestrator.iteration", `SDK message received (#${messageCount})`, {
150→          sessionId,
151→          messageType: msg.type,
152→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
153→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
154→        });
155→
156→        // Check if session has reached terminal status
157→        const currentStatus = await deps.getSessionStatus(sessionId);
158→        if (TERMINAL_STATUSES.has(currentStatus)) {
159→          log.info("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
160→          break;
161→        }
162→
163→        // Transition to active on first message
164→        if (!firstMessageReceived) {
165→          firstMessageReceived = true;
166→          await deps.updateSessionStatus(sessionId, "active");
167→        }
168→
169→        // Forward through event bridge (transform + emit + stall detection)
170→        bridge.handleMessage(msg);
171→      }
172→      log.info("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
173→      // Transition to idle when stream ends normally and agent produced output
174→      if (firstMessageReceived) {
175→        const finalStatus = await deps.getSessionStatus(sessionId);
176→        if (!TERMINAL_STATUSES.has(finalStatus)) {
177→          await deps.updateSessionStatus(sessionId, "idle");
178→        }
179→      }
180→    } catch (err) {
181→      const errorMessage = err instanceof Error ? err.message : String(err);
182→      log.error("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
183→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
184→    } finally {
185→      if (!firstMessageReceived) {
186→        log.warn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
187→      }
188→      bridge.stop();
189→    }
190→  }
191→
192→  return iterate();
193→}
194→
195→// ---------------------------------------------------------------------------
196→// Pure helpers
197→// ---------------------------------------------------------------------------
198→
199→export function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
200→  const result: Record<string, unknown> = {};
201→  for (const [key, value] of Object.entries(obj)) {
202→    if (value !== undefined) {
203→      result[key] = value;
204→    }
205→  }
206→  return result as Partial<T>;
207→}
208→
209→function sessionNotFound(sessionId: string): SessionError {
210→  return {
211→    code: "SESSION_NOT_FOUND",
212→    message: `Session not found: ${sessionId}`,
213→    httpStatus: 404,
214→  };
215→}
216→
217→function worktreeError(message: string): SessionError {
218→  return {
219→    code: "WORKTREE_ERROR",
220→    message,
221→    httpStatus: 500,
222→  };
223→}
224→
225→function fromAssignmentError(error: AssignmentError): SessionError {
226→  return {
227→    code: error.code as SessionErrorCode,
228→    message: error.message,
229→    httpStatus: error.httpStatus,
230→  };
231→}
232→
233→// ---------------------------------------------------------------------------
234→// Session row shape (DB query result)
235→// ---------------------------------------------------------------------------
236→
237→type SessionRow = {
238→  id: RecordId<"agent_session", string>;
239→  orchestrator_status?: string;
240→  worktree_branch?: string;
241→  worktree_path?: string;
242→  started_at?: string;
243→  last_event_at?: string;
244→  task_id?: RecordId<"task", string>;
245→  workspace?: RecordId<"workspace", string>;
246→  error_message?: string;
247→  external_session_id?: string;
248→  session_type?: string;
249→};
250→
251→type SessionLookup =
252→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
253→  | { ok: false; error: SessionError };
254→
255→async function lookupSession(
256→  surreal: Surreal,
257→  sessionId: string,
258→): Promise<SessionLookup> {
259→  const record = new RecordId("agent_session", sessionId);
260→  const session = await surreal.select<SessionRow>(record);
261→  if (!session) {
262→    return { ok: false, error: sessionNotFound(sessionId) };
263→  }
264→  if (!session.orchestrator_status) {
265→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
266→  }
267→  const status = session.orchestrator_status as OrchestratorStatus;
268→  return { ok: true, session, record, status };
269→}
270→
271→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
272→  if (!session.workspace) {
273→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
274→  }
275→  return session.workspace as RecordId<"workspace", string>;
276→}
277→
278→function generateStreamId(sessionId: string): string {
279→  return `stream-${sessionId}`;
280→}
281→
282→// ---------------------------------------------------------------------------
283→// createOrchestratorSession
284→// ---------------------------------------------------------------------------
285→
286→type CreateSessionInput = {
287→  surreal: Surreal;
288→  shellExec: ShellExec;
289→  brainBaseUrl: string;
290→  workspaceId: string;
291→  taskId: string;
292→  intentId?: string;
293→  authToken?: string;
294→  adapter: SandboxAgentAdapter;
295→  sandboxAgentType?: string;
296→  validateAssignment: (
297→    surreal: Surreal,
298→    workspaceId: string,
299→    taskId: string,
300→  ) => Promise<AssignmentResult>;
301→  createAgentSession: (input: {
302→    surreal: Surreal;
303→    agent: string;
304→    workspaceRecord: RecordId<"workspace", string>;
305→    taskId?: string;
306→  }) => Promise<{ session_id: string }>;
307→};
308→
309→export async function createOrchestratorSession(
310→  input: CreateSessionInput,
311→): Promise<OrchestratorSessionResult> {
312→  // 0. Intent authorization gate (optional — backwards compatible)
313→  if (input.intentId) {
314→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
315→    if (!gateResult.ok) {
316→      return { ok: false, error: gateResult.error };
317→    }
318→  }
319→
320→  // 1. Validate assignment eligibility
321→  const assignmentResult = await input.validateAssignment(
322→    input.surreal,
323→    input.workspaceId,
324→    input.taskId,
325→  );
326→
327→  if (!assignmentResult.ok) {
328→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
329→  }
330→
331→  const { validation } = assignmentResult;
332→
333→  return createSessionViaAdapter(input, validation);
334→}
335→
336→// ---------------------------------------------------------------------------
337→// Intent authorization helpers
338→// ---------------------------------------------------------------------------
339→
340→async function checkIntentAuthorization(
341→  surreal: Surreal,
342→  intentId: string,
343→  workspaceId: string,
344→): Promise<SessionResult<void>> {
345→  const intent = await getIntentById(surreal, intentId);
346→  if (!intent) {
347→    return {
348→      ok: false,
349→      error: {
350→        code: "INTENT_NOT_AUTHORIZED",
351→        message: `Intent ${intentId} not found`,
352→        httpStatus: 404,
353→      },
354→    };
355→  }
356→
357→  // Validate workspace scope: intent must belong to the session's workspace
358→  const intentWorkspaceId = intent.workspace.id as string;
359→  if (intentWorkspaceId !== workspaceId) {
360→    return {
361→      ok: false,
362→      error: {
363→        code: "WORKSPACE_MISMATCH",
364→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
365→        httpStatus: 403,
366→      },
367→    };
368→  }
369→
370→  const status = intent.status as IntentStatus;
371→  if (status !== "authorized") {
372→    return {
373→      ok: false,
374→      error: {
375→        code: "INTENT_NOT_AUTHORIZED",
376→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
377→        httpStatus: 403,
378→      },
379→    };
380→  }
381→
382→  return { ok: true, value: undefined as void };
383→}
384→
385→async function transitionIntentToExecuting(
386→  surreal: Surreal,
387→  intentId: string,
388→  sessionRecord: RecordId<"agent_session", string>,
389→): Promise<void> {
390→  await updateIntentStatus(surreal, intentId, "executing");
391→
392→  const intentRecord = new RecordId("intent", intentId);
393→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
394→  await surreal.query(
395→    "RELATE $intent->gates->$sess SET created_at = time::now();",
396→    { intent: intentRecord, sess: sessionRecord },
397→  );
398→
399→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
400→    intentId,
401→    sessionId: sessionRecord.id as string,
402→  });
403→}
404→
405→// ---------------------------------------------------------------------------
406→// Adapter-based session creation
407→// ---------------------------------------------------------------------------
408→
409→function slugFromTitle(title: string): string {
410→  return title
411→    .toLowerCase()
412→    .replace(/[^a-z0-9]+/g, "-")
413→    .replace(/^-|-$/g, "")
414→    .slice(0, 50);
415→}
416→
417→async function createSessionViaAdapter(
418→  input: CreateSessionInput,
419→  validation: import("./types").AssignmentValidation,
420→): Promise<OrchestratorSessionResult> {
421→  const adapter = input.adapter;
422→  const repoRoot = validation.repoPath;
423→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
424→
425→  // 1. Create worktree for isolated agent work
426→  const worktreeResult = await createWorktree(
427→    input.shellExec,
428→    repoRoot,
429→    taskSlug,
430→  );
431→
432→  if (!worktreeResult.ok) {
433→    return {
434→      ok: false,
435→      error: worktreeError(worktreeResult.error.message),
436→    };
437→  }
438→
439→  const { branchName, worktreePath } = worktreeResult.value;
440→
441→  // 2. Create agent_session record
442→  const { session_id: agentSessionId } = await input.createAgentSession({
443→    surreal: input.surreal,
444→    agent: "claude",
445→    workspaceRecord: validation.workspaceRecord,
446→    taskId: input.taskId,
447→  });
448→
449→  const streamId = generateStreamId(agentSessionId);
450→
451→  // 3. Create session via adapter — agent works in worktree, not main repo
452→  let handle: SessionHandle;
453→  try {
454→    handle = await adapter.createSession({
455→      agent: input.sandboxAgentType ?? "claude",
456→      cwd: worktreePath,
457→    });
458→  } catch (err) {
459→    // Rollback: remove worktree and delete agent_session on adapter failure
460→    await removeWorktree(input.shellExec, repoRoot, branchName);
461→    const sessionRecord = new RecordId("agent_session", agentSessionId);
462→    await input.surreal.delete(sessionRecord);
463→    return {
464→      ok: false,
465→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
466→    };
467→  }
468→
469→  // 4. Update agent_session with sandbox + worktree fields
470→  const sessionRecord = new RecordId("agent_session", agentSessionId);
471→  await input.surreal.update(sessionRecord).merge({
472→    orchestrator_status: "spawning" as OrchestratorStatus,
473→    stream_id: streamId,
474→    session_type: "sandbox_agent",
475→    provider: "local",
476→    external_session_id: handle.id,
477→    worktree_branch: branchName,
478→    worktree_path: worktreePath,
479→  });
480→
481→  // 5. Transition intent to executing
482→  if (input.intentId) {
483→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
484→  }
485→
486→  return {
487→    ok: true,
488→    value: {
489→      agentSessionId,
490→      streamId,
491→      worktreeBranch: branchName,
492→      sessionHandle: handle,
493→    },
494→  };
495→}
