836→    if (TERMINAL_STATUSES.has(status)) {
837→      return { ok: false, error: sessionNotFound(input.sessionId) };
838→    }
839→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
840→  }
841→
842→  if (!session.external_session_id) {
