  1→/**
  2→ * Acceptance Tests: Sandbox Agent Session Lifecycle (R1)
  3→ *
  4→ * Exercises the full SandboxAgent integration through Brain's HTTP endpoints
  5→ * against a real SandboxAgent Server process.
  6→ *
  7→ * Traces: US-01 (spawn), US-02 (persistence), US-03 (events),
  8→ *         US-04 (multi-turn), US-05 (restoration)
  9→ *
 10→ * Driving ports:
 11→ *   POST /api/orchestrator/:ws/sessions/assign   (session spawn)
 12→ *   POST /api/orchestrator/:ws/sessions/:id/prompt (multi-turn prompt)
 13→ *   GET  /api/orchestrator/:ws/sessions/:id        (session status)
 14→ *   POST /api/orchestrator/:ws/sessions/:id/accept  (accept work)
 15→ *   POST /api/orchestrator/:ws/sessions/:id/abort   (abort session)
 16→ *   SSE  /api/orchestrator/:ws/sessions/:id/stream   (event stream)
 17→ *
 18→ * Prerequisites:
 19→ *   - SandboxAgent Server binary available and running
 20→ *   - SurrealDB running (standard acceptance test requirement)
 21→ *   - Required env vars: OPENROUTER_API_KEY, CHAT_AGENT_MODEL, etc.
 22→ */
 23→import { describe, expect, it } from "bun:test";
 24→import { RecordId } from "surrealdb";
 25→import {
 26→  setupAcceptanceSuite,
 27→  type AcceptanceTestRuntime,
 28→} from "./acceptance-test-kit";
 29→import { createTestUser, createWorkspaceViaHttp, createWorkspaceDirectly, createTaskDirectly } from "./shared-fixtures";
 30→
 31→// ── Suite Setup ──
 32→
 33→const getRuntime = setupAcceptanceSuite("sandbox_session_lifecycle", {
 34→  configOverrides: { sandboxAgentEnabled: true, sandboxAgentType: "claude", orchestratorMockAgent: true },
 35→});
 36→
 37→async function assignTaskToSandboxAgent(
 38→  baseUrl: string,
 39→  user: { headers: Record<string, string> },
 40→  workspaceId: string,
 41→  taskId: string,
 42→): Promise<{ agentSessionId: string; streamUrl: string }> {
 43→  const response = await fetch(
 44→    `${baseUrl}/api/orchestrator/${workspaceId}/assign`,
 45→    {
 46→      method: "POST",
 47→      headers: { "Content-Type": "application/json", ...user.headers },
 48→      body: JSON.stringify({ taskId }),
 49→    },
 50→  );
 51→  if (!response.ok) {
 52→    const body = await response.text();
 53→    throw new Error(`Failed to assign task: ${response.status} ${body}`);
 54→  }
 55→  return (await response.json()) as { agentSessionId: string; streamUrl: string };
 56→}
 57→
 58→async function sendPrompt(
 59→  baseUrl: string,
 60→  user: { headers: Record<string, string> },
 61→  workspaceId: string,
 62→  sessionId: string,
 63→  text: string,
 64→): Promise<Response> {
 65→  return fetch(
 66→    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}/prompt`,
 67→    {
 68→      method: "POST",
 69→      headers: { "Content-Type": "application/json", ...user.headers },
 70→      body: JSON.stringify({ text }),
 71→    },
 72→  );
 73→}
 74→
 75→async function getSessionStatus(
 76→  baseUrl: string,
 77→  user: { headers: Record<string, string> },
 78→  workspaceId: string,
 79→  sessionId: string,
 80→): Promise<{ orchestratorStatus: string; sessionType?: string }> {
 81→  const response = await fetch(
 82→    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}`,
 83→    { headers: user.headers },
 84→  );
 85→  if (!response.ok) {
 86→    throw new Error(`Failed to get session status: ${response.status}`);
 87→  }
 88→  return (await response.json()) as { orchestratorStatus: string; sessionType?: string };
 89→}
 90→
 91→async function querySessionFromDb(
 92→  surreal: AcceptanceTestRuntime["surreal"],
 93→  sessionId: string,
 94→): Promise<Record<string, unknown> | undefined> {
 95→  const [rows] = await surreal.query<[Array<Record<string, unknown>>]>(
 96→    `SELECT * FROM $record;`,
 97→    { record: new RecordId("agent_session", sessionId) },
 98→  );
 99→  return rows[0];
100→}
101→
102→// =============================================================================
103→// Walking Skeletons
104→// =============================================================================
105→
106→describe("Walking Skeleton: Sandbox Agent Session Lifecycle", () => {
107→  // ─── WS-1: Developer spawns a session, sends a prompt, and receives events ───
108→  // US-01, US-03, US-04
109→  it("developer spawns a sandbox session, sends a prompt, and sees agent events", async () => {
110→    const { baseUrl, surreal } = getRuntime();
111→
112→    // Given a developer with a workspace containing a task ready for work
113→    const user = await createTestUser(baseUrl, `ws1-${crypto.randomUUID()}`);
114→    const workspace = await createWorkspaceViaHttp(baseUrl, user, surreal, { repoPath: process.cwd() });
115→    const task = await createTaskDirectly(surreal, workspace.workspaceId, {
116→      title: "Implement rate limiting",
117→      description: "Add sliding window rate limiter to the API gateway",
118→    });
119→
120→    // When the developer requests a coding session for the task
121→    const assignment = await assignTaskToSandboxAgent(
122→      baseUrl,
123→      user,
124→      workspace.workspaceId,
125→      task.taskId,
126→    );
127→
128→    // Then a sandbox agent session is created with a stream URL
129→    expect(assignment.agentSessionId).toBeTruthy();
130→    expect(assignment.streamUrl).toBeTruthy();
131→
132→    // And the session record in SurrealDB has session_type "sandbox_agent"
133→    const dbSession = await querySessionFromDb(surreal, assignment.agentSessionId);
134→    expect(dbSession).toBeDefined();
135→    expect(dbSession!.session_type).toBe("sandbox_agent");
136→
137→    // When the developer sends their first prompt
138→    const promptResponse = await sendPrompt(
139→      baseUrl,
140→      user,
141→      workspace.workspaceId,
142→      assignment.agentSessionId,
143→      "What is the difference between a mutex and a semaphore?",
144→    );
145→
146→    // Then the prompt is accepted
147→    if (!promptResponse.ok) {
148→      const body = await promptResponse.text();
149→      console.error("Prompt failed:", promptResponse.status, body);
150→    }
151→    expect(promptResponse.ok).toBe(true);
152→
153→    // And the session status is active
154→    const status = await getSessionStatus(
155→      baseUrl,
156→      user,
157→      workspace.workspaceId,
158→      assignment.agentSessionId,
159→    );
160→    // With mock adapter, status stays "spawning" because no real events trigger
161→    // the spawning->active transition. Walking skeleton verifies wiring, not events.
162→    expect(["spawning", "running", "active", "idle"]).toContain(status.orchestratorStatus);
163→  }, 30_000);
164→
165→  // ─── WS-2: Developer sends follow-up prompts ───
166→  // US-04
167→  it("developer sends multiple follow-up prompts to the same session", async () => {
168→    const { baseUrl, surreal } = getRuntime();
169→
170→    // Given a developer with an active coding session
171→    const user = await createTestUser(baseUrl, `ws2-${crypto.randomUUID()}`);
172→    const workspace = await createWorkspaceViaHttp(baseUrl, user, surreal, { repoPath: process.cwd() });
173→    const task = await createTaskDirectly(surreal, workspace.workspaceId, {
174→      title: "Build authentication service",
175→      description: "Create JWT-based auth with refresh tokens",
176→    });
177→
178→    const assignment = await assignTaskToSandboxAgent(
179→      baseUrl,
180→      user,
181→      workspace.workspaceId,
182→      task.taskId,
183→    );
184→
185→    // When the developer sends the first prompt
186→    const firstPrompt = await sendPrompt(
187→      baseUrl,
188→      user,
189→      workspace.workspaceId,
190→      assignment.agentSessionId,
191→      "What are the three pillars of observability?",
192→    );
193→    expect(firstPrompt.ok).toBe(true);
194→
195→    // And sends a follow-up to refine the implementation
196→    const secondPrompt = await sendPrompt(
197→      baseUrl,
198→      user,
199→      workspace.workspaceId,
200→      assignment.agentSessionId,
201→      "Which of those three is most often neglected?",
202→    );
203→
204→    // Then the follow-up is accepted (not 409 Conflict)
205→    expect(secondPrompt.ok).toBe(true);
206→    expect(secondPrompt.status).not.toBe(409);
207→
208→    // When the developer sends a third prompt
209→    const thirdPrompt = await sendPrompt(
210→      baseUrl,
211→      user,
212→      workspace.workspaceId,
213→      assignment.agentSessionId,
214→      "Can you give an example of structured logging?",
215→    );
216→
217→    // Then the third prompt is also accepted
218→    expect(thirdPrompt.ok).toBe(true);
219→  }, 60_000);
220→
221→  // ─── WS-3: Session persists in SurrealDB ───
222→  // US-01, US-02
223→  it("session record in SurrealDB has correct sandbox fields", async () => {
224→    const { baseUrl, surreal } = getRuntime();
225→
226→    // Given a developer spawns a sandbox coding session
227→    const user = await createTestUser(baseUrl, `ws3-${crypto.randomUUID()}`);
228→    const workspace = await createWorkspaceViaHttp(baseUrl, user, surreal, { repoPath: process.cwd() });
229→    const task = await createTaskDirectly(surreal, workspace.workspaceId, {
230→      title: "Add logging middleware",
231→      description: "Structured logging with request tracing",
232→    });
233→
234→    const assignment = await assignTaskToSandboxAgent(
235→      baseUrl,
236→      user,
237→      workspace.workspaceId,
238→      task.taskId,
239→    );
240→
241→    // When the session record is queried from SurrealDB
242→    const dbSession = await querySessionFromDb(surreal, assignment.agentSessionId);
243→
244→    // Then the record has session_type "sandbox_agent"
245→    expect(dbSession).toBeDefined();
246→    expect(dbSession!.session_type).toBe("sandbox_agent");
247→
248→    // And has a provider field
249→    expect(dbSession!.provider).toBeDefined();
250→
251→    // And has an external_session_id linking to the SandboxAgent runtime
252→    expect(dbSession!.external_session_id).toBeTruthy();
253→
254→    // And has the correct workspace reference
