537→      { task: taskRecord },
538→    );
539→    const taskTitle = taskRows[0]?.title?.trim();
540→    const taskDescription = taskRows[0]?.description?.trim();
541→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
542→    const descriptionSuffix = taskDescription && taskDescription.length > 0
543→      ? ` Task description: ${taskDescription}`
544→      : "";
545→
546→    return {
547→      goal: `Complete task: ${taskLabel}`,
548→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
549→    };
550→  };
551→
552→  // Resolve adapter: real SDK adapter from deps, or mock for tests
553→  const sandboxAdapterPromise = wiringDeps.sandboxAgentAdapter
554→    ? Promise.resolve(wiringDeps.sandboxAgentAdapter)
555→    : wiringDeps.mockAgent
556→      ? import("./sandbox-adapter").then((mod) => mod.createMockAdapter())
557→      : Promise.reject(new Error("No sandbox adapter configured — set sandboxAgentAdapter or mockAgent"));
558→
559→  const routeDeps: OrchestratorRouteDeps = {
560→    createSession: async (workspaceId, taskId, authToken) => {
561→      const [adapter, lifecycle, queries, guard, stallDetector] = await Promise.all([
562→        sandboxAdapterPromise,
563→        lifecycleImport,
564→        queriesImport,
565→        guardImport,
566→        stallDetectorImport,
567→      ]);
568→
569→      // Build task-scoped intent context, issue MCP auth env with intent
570→      const { goal, reasoning } = await buildTaskScopedIntentContext(taskId);
571→      const { identityId } = await issueProxyTokenForWorkspace(workspaceId, authToken);
572→      const mcpAuth = await issueBrainMcpAuthEnv(workspaceId, identityId, goal, reasoning);
573→      const intentRecord = new RecordId("intent", mcpAuth.intentId);
574→
575→      // Issue a governed proxy token (revoke the ungoverned one from issueProxyTokenForWorkspace)
576→      const workspaceRecord = new RecordId("workspace", workspaceId);
577→      const identityRecord = new RecordId("identity", identityId);
578→      const rawToken = generateProxyToken();
579→      const tokenHash = hashProxyToken(rawToken);
580→      const expiresAt = computeExpiresAt(proxyTokenTtlDays);
581→
582→      // Build proxy env for the sandbox agent
583→      const proxyEnv: Record<string, string> = {
584→        ...mcpAuth.env,
585→        ANTHROPIC_BASE_URL: `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic`,
586→        X_BRAIN_AUTH: rawToken,
587→      };
588→
589→      const result = await lifecycle.createOrchestratorSession({
590→        surreal: wiringDeps.surreal,
591→        shellExec: wiringDeps.shellExec,
592→        brainBaseUrl: wiringDeps.brainBaseUrl,
593→        workspaceId,
594→        taskId,
595→        env: proxyEnv,
596→        validateAssignment: guard.validateAssignment,
597→        createAgentSession: queries.createAgentSession,
598→        adapter,
599→        sandboxAgentType: wiringDeps.sandboxAgentType,
600→      });
601→
602→      // After session creation, create the governed proxy token with intent + session
603→      if (result.ok) {
604→        const sessionRecord = new RecordId("agent_session", result.value.agentSessionId);
605→
606→        // Revoke the ungoverned token and create a governed one
607→        await wiringDeps.surreal.query(
608→          `UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;`,
609→          { identity: identityRecord, ws: workspaceRecord },
610→        );
611→
612→        const contentFields: Record<string, unknown> = {
613→          token_hash: tokenHash,
614→          workspace: workspaceRecord,
615→          identity: identityRecord,
616→          expires_at: expiresAt,
617→          created_at: new Date(),
618→          revoked: false,
619→          intent: intentRecord,
620→          session: sessionRecord,
621→        };
622→
623→        await wiringDeps.surreal.query(
624→          `CREATE proxy_token CONTENT $content;`,
625→          { content: contentFields },
626→        );
627→      }
628→
629→      // Wire SSE stream + event iteration on success
630→      if (result.ok && wiringDeps.sseRegistry) {
631→        const { agentSessionId, streamId, sessionHandle } = result.value;
632→        wiringDeps.sseRegistry.registerMessage(streamId);
633→
634→        // Wire sandbox event bridge for real-time SSE events
635→        if (sessionHandle) {
636→          const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
637→          const bridge = createSandboxEventBridge(
638→            {
639→              emitEvent: wiringDeps.sseRegistry.emitEvent,
640→              updateLastEventAt: async (sid) => {
641→                const rec = new RecordId("agent_session", sid);
642→                await wiringDeps.surreal.update(rec).merge({
643→                  last_event_at: new Date(),
644→                });
645→              },
646→              notifyStallDetector: () => {
647→                // Stall detector integration deferred to later step
648→              },
649→            },
650→            streamId,
651→            agentSessionId,
652→          );
653→          sessionHandle.onEvent((event) => {
654→            bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
655→          });
656→        }
657→      }
658→
659→      return result;
660→    },
661→
662→    getSessionStatus: async (sessionId) => {
663→      const lifecycle = await lifecycleImport;
664→      return lifecycle.getOrchestratorSessionStatus({
665→        surreal: wiringDeps.surreal,
666→        sessionId,
667→      });
668→    },
669→
670→    abortSession: async (sessionId) => {
671→      const [adapter, lifecycle, queries] = await Promise.all([
672→        sandboxAdapterPromise,
673→        lifecycleImport,
674→        queriesImport,
675→      ]);
676→      return lifecycle.abortOrchestratorSession({
677→        surreal: wiringDeps.surreal,
678→        shellExec: wiringDeps.shellExec,
679→        resolveRepoRoot,
680→        sessionId,
681→        adapter,
682→        endAgentSession: queries.endAgentSession,
683→      });
684→    },
685→
686→    acceptSession: async (sessionId, summary) => {
687→      const [adapter, lifecycle, queries] = await Promise.all([
688→        sandboxAdapterPromise,
689→        lifecycleImport,
690→        queriesImport,
691→      ]);
692→      return lifecycle.acceptOrchestratorSession({
693→        surreal: wiringDeps.surreal,
694→        shellExec: wiringDeps.shellExec,
695→        resolveRepoRoot,
696→        sessionId,
697→        summary,
698→        adapter,
699→        endAgentSession: queries.endAgentSession,
700→      });
701→    },
702→
703→    getReview: async (sessionId) => {
704→      const [lifecycle, worktreeManager] = await Promise.all([
705→        lifecycleImport,
706→        import("./worktree-manager"),
707→      ]);
708→      return lifecycle.getOrchestratorReview({
709→        surreal: wiringDeps.surreal,
710→        sessionId,
711→        resolveRepoRoot,
712→        getDiff: (repoRoot: string, branchName: string) =>
713→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
714→        getTaskTitle: async (taskId: string) => {
715→          const { RecordId } = await import("surrealdb");
716→          const taskRecord = new RecordId("task", taskId);
717→          const rows = (await wiringDeps.surreal.query(
718→            `SELECT title FROM $task;`,
719→            { task: taskRecord },
720→          )) as Array<Array<{ title: string }>>;
721→          return rows[0]?.[0]?.title ?? "";
722→        },
723→      });
724→    },
725→
726→    rejectSession: async (sessionId, feedback) => {
727→      const lifecycle = await lifecycleImport;
728→      return lifecycle.rejectOrchestratorSession({
729→        surreal: wiringDeps.surreal,
730→        sessionId,
731→        feedback,
732→      });
733→    },
734→
735→    sendPrompt: async (sessionId, text) => {
736→      const [adapter, lifecycle] = await Promise.all([sandboxAdapterPromise, lifecycleImport]);
737→      return lifecycle.sendSessionPrompt({
738→        surreal: wiringDeps.surreal,
739→        sessionId,
740→        text,
741→        adapter,
742→      });
743→    },
744→  };
745→
746→  const handlers = createOrchestratorRouteHandlers(routeDeps);
747→
748→  // Wrap handler with workspace access check
749→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
750→    const workspaceId = request.params.workspaceId;
751→    if (workspaceId) {
752→      const accessError = await validateWorkspaceAccess(request, workspaceId);
753→      if (accessError) return accessError;
754→    }
755→    return handler(request);
756→  };
757→
758→  const streamHandler = wiringDeps.sseRegistry
759→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
760→    : undefined;
761→
762→  return {
763→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
764→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
765→    accept: withTracing("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
766→    abort: withTracing("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
767→    review: withTracing("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
768→    reject: withTracing("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
769→    prompt: withTracing("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
770→    ...(streamHandler
771→      ? { stream: withTracing("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
772→      : {}),
773→  };
774→}
775→

