  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { ShellExec } from "./worktree-manager";
  3→import { createWorktree, removeWorktree } from "./worktree-manager";
  4→import type { AssignmentResult } from "./assignment-guard";
  5→import type { AssignmentError, OrchestratorStatus } from "./types";
  6→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  7→import { startEventBridge, type SdkMessage } from "./event-bridge";
  8→import type { StreamEvent } from "../../shared/contracts";
  9→import type { StallDetectorHandle } from "./stall-detector";
 10→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 11→import type { IntentStatus } from "../intent/types";
 12→import { log } from "../telemetry/logger";
 13→import type { SandboxAgentAdapter, SessionHandle } from "./sandbox-adapter";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types — exported for tests
 17→// ---------------------------------------------------------------------------
 18→
 19→export type SessionDeps = {
 20→  surreal: Surreal;
 21→  shellExec: ShellExec;
 22→  brainBaseUrl: string;
 23→};
 24→
 25→export type SessionErrorCode =
 26→  | "TASK_NOT_FOUND"
 27→  | "TASK_NOT_ASSIGNABLE"
 28→  | "AGENT_ALREADY_ACTIVE"
 29→  | "WORKSPACE_MISMATCH"
 30→  | "MISSING_TASK_ID"
 31→  | "WORKTREE_ERROR"
 32→  | "SESSION_NOT_FOUND"
 33→  | "SESSION_ERROR"
 34→  | "INTENT_NOT_AUTHORIZED";
 35→
 36→export type SessionError = {
 37→  code: SessionErrorCode;
 38→  message: string;
 39→  httpStatus: number;
 40→};
 41→
 42→export type SessionResult<T> =
 43→  | { ok: true; value: T }
 44→  | { ok: false; error: SessionError };
 45→
 46→export type OrchestratorSessionResult = SessionResult<{
 47→  agentSessionId: string;
 48→  streamId: string;
 49→  worktreeBranch: string;
 50→  sessionHandle?: SessionHandle;
 51→}>;
 52→
 53→export type SessionStatusResult = SessionResult<{
 54→  orchestratorStatus: OrchestratorStatus;
 55→  worktreeBranch?: string;
 56→  worktreePath?: string;
 57→  lastEventAt?: string;
 58→  startedAt?: string;
 59→  error?: string;
 60→}>;
 61→
 62→export type AbortSessionResult = SessionResult<{
 63→  aborted: boolean;
 64→  sessionId: string;
 65→}>;
 66→
 67→export type AcceptSessionResult = SessionResult<{
 68→  accepted: boolean;
 69→  sessionId: string;
 70→}>;
 71→
 72→export type ReviewResult = SessionResult<{
 73→  taskTitle: string;
 74→  diff: import("./worktree-manager").DiffResult;
 75→  session: {
 76→    orchestratorStatus: string;
 77→    worktreeBranch?: string;
 78→    startedAt?: string;
 79→    lastEventAt?: string;
 80→    toolCallCount?: number;
 81→    filesEdited?: number;
 82→  };
 83→}>;
 84→
 85→export type RejectSessionResult = SessionResult<{
 86→  rejected: boolean;
 87→  continuing: boolean;
 88→}>;
 89→
 90→export type PromptSessionResult = SessionResult<{
 91→  delivered: boolean;
 92→}>;
 93→
 94→// ---------------------------------------------------------------------------
 95→// Event iteration — port (dependencies as function signatures)
 96→// ---------------------------------------------------------------------------
 97→
 98→export type EventIterationDeps = {
 99→  emitEvent: (streamId: string, event: StreamEvent) => void;
100→  updateSessionStatus: (
101→    sessionId: string,
102→    status: OrchestratorStatus,
103→    error?: string,
104→  ) => Promise<void>;
105→  updateLastEventAt: (sessionId: string) => Promise<void>;
106→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
107→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
108→};
109→
110→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
111→  TERMINAL_ORCHESTRATOR_STATUSES,
112→);
113→
114→/**
115→ * Iterates the SDK message stream, forwarding messages through the event
116→ * bridge. Transitions session to "active" on first message, starts stall
117→ * detection, and stops on terminal status or error.
118→ *
119→ * Returns a Promise that resolves when iteration ends (for testing).
120→ * In production, this is launched fire-and-forget.
121→ */
122→export function startEventIteration(
123→  deps: EventIterationDeps,
124→  messageStream: AsyncIterable<unknown>,
125→  streamId: string,
126→  sessionId: string,
127→): Promise<void> {
128→  const stallDetector = deps.startStallDetector(sessionId, streamId);
129→
130→  const bridge = startEventBridge(
131→    {
132→      emitEvent: deps.emitEvent,
133→      updateLastEventAt: deps.updateLastEventAt,
134→    },
135→    streamId,
136→    sessionId,
137→    stallDetector,
138→  );
139→
140→  let firstMessageReceived = false;
141→  let messageCount = 0;
142→
143→  async function iterate(): Promise<void> {
144→    log.info("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
145→    try {
146→      for await (const rawMessage of messageStream) {
147→        messageCount++;
148→        const msg = rawMessage as SdkMessage;
149→        log.info("orchestrator.iteration", `SDK message received (#${messageCount})`, {
150→          sessionId,
151→          messageType: msg.type,
152→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
153→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
154→        });
155→
156→        // Check if session has reached terminal status
157→        const currentStatus = await deps.getSessionStatus(sessionId);
158→        if (TERMINAL_STATUSES.has(currentStatus)) {
159→          log.info("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
160→          break;
161→        }
162→
163→        // Transition to active on first message
164→        if (!firstMessageReceived) {
165→          firstMessageReceived = true;
166→          await deps.updateSessionStatus(sessionId, "active");
167→        }
168→
169→        // Forward through event bridge (transform + emit + stall detection)
170→        bridge.handleMessage(msg);
171→      }
172→      log.info("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
173→      // Transition to idle when stream ends normally and agent produced output
174→      if (firstMessageReceived) {
175→        const finalStatus = await deps.getSessionStatus(sessionId);
176→        if (!TERMINAL_STATUSES.has(finalStatus)) {
177→          await deps.updateSessionStatus(sessionId, "idle");
178→        }
179→      }
180→    } catch (err) {
181→      const errorMessage = err instanceof Error ? err.message : String(err);
182→      log.error("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
183→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
184→    } finally {
185→      if (!firstMessageReceived) {
186→        log.warn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
187→      }
188→      bridge.stop();
189→    }
190→  }
191→
192→  return iterate();
193→}
194→
195→// ---------------------------------------------------------------------------
196→// Pure helpers
197→// ---------------------------------------------------------------------------
198→
199→export function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
200→  const result: Record<string, unknown> = {};
201→  for (const [key, value] of Object.entries(obj)) {
202→    if (value !== undefined) {
203→      result[key] = value;
204→    }
205→  }
206→  return result as Partial<T>;
207→}
208→
209→function sessionNotFound(sessionId: string): SessionError {
210→  return {
211→    code: "SESSION_NOT_FOUND",
212→    message: `Session not found: ${sessionId}`,
213→    httpStatus: 404,
214→  };
215→}
216→
217→function worktreeError(message: string): SessionError {
218→  return {
219→    code: "WORKTREE_ERROR",
220→    message,
221→    httpStatus: 500,
222→  };
223→}
224→
225→function fromAssignmentError(error: AssignmentError): SessionError {
226→  return {
227→    code: error.code as SessionErrorCode,
228→    message: error.message,
229→    httpStatus: error.httpStatus,
230→  };
231→}
232→
233→// ---------------------------------------------------------------------------
234→// Session row shape (DB query result)
235→// ---------------------------------------------------------------------------
236→
237→type SessionRow = {
238→  id: RecordId<"agent_session", string>;
239→  orchestrator_status?: string;
240→  worktree_branch?: string;
241→  worktree_path?: string;
242→  started_at?: string;
243→  last_event_at?: string;
244→  task_id?: RecordId<"task", string>;
245→  workspace?: RecordId<"workspace", string>;
246→  error_message?: string;
247→  external_session_id?: string;
248→  session_type?: string;
249→};
250→
251→type SessionLookup =
252→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
253→  | { ok: false; error: SessionError };
254→
255→async function lookupSession(
256→  surreal: Surreal,
257→  sessionId: string,
258→): Promise<SessionLookup> {
259→  const record = new RecordId("agent_session", sessionId);
260→  const session = await surreal.select<SessionRow>(record);
261→  if (!session) {
262→    return { ok: false, error: sessionNotFound(sessionId) };
263→  }
264→  if (!session.orchestrator_status) {
265→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
266→  }
267→  const status = session.orchestrator_status as OrchestratorStatus;
268→  return { ok: true, session, record, status };
269→}
270→
271→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
272→  if (!session.workspace) {
273→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
274→  }
275→  return session.workspace as RecordId<"workspace", string>;
276→}
277→
278→function generateStreamId(sessionId: string): string {
279→  return `stream-${sessionId}`;
280→}
281→
282→// ---------------------------------------------------------------------------
283→// createOrchestratorSession
284→// ---------------------------------------------------------------------------
285→
286→type CreateSessionInput = {
287→  surreal: Surreal;
288→  shellExec: ShellExec;
289→  brainBaseUrl: string;
290→  workspaceId: string;
291→  taskId: string;
292→  intentId?: string;
293→  authToken?: string;
294→  env?: Record<string, string>;
295→  adapter: SandboxAgentAdapter;
296→  sandboxAgentType?: string;
297→  validateAssignment: (
298→    surreal: Surreal,
299→    workspaceId: string,
300→    taskId: string,
301→  ) => Promise<AssignmentResult>;
302→  createAgentSession: (input: {
303→    surreal: Surreal;
304→    agent: string;
305→    workspaceRecord: RecordId<"workspace", string>;
306→    taskId?: string;
307→  }) => Promise<{ session_id: string }>;
308→};
309→
310→export async function createOrchestratorSession(
311→  input: CreateSessionInput,
312→): Promise<OrchestratorSessionResult> {
313→  // 0. Intent authorization gate (optional — backwards compatible)
314→  if (input.intentId) {
315→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
316→    if (!gateResult.ok) {
317→      return { ok: false, error: gateResult.error };
318→    }
319→  }
320→
321→  // 1. Validate assignment eligibility
322→  const assignmentResult = await input.validateAssignment(
323→    input.surreal,
324→    input.workspaceId,
325→    input.taskId,
326→  );
327→
328→  if (!assignmentResult.ok) {
329→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
330→  }
331→
332→  const { validation } = assignmentResult;
333→
334→  return createSessionViaAdapter(input, validation);
335→}
336→
337→// ---------------------------------------------------------------------------
338→// Intent authorization helpers
339→// ---------------------------------------------------------------------------
340→
341→async function checkIntentAuthorization(
342→  surreal: Surreal,
343→  intentId: string,
344→  workspaceId: string,
345→): Promise<SessionResult<void>> {
346→  const intent = await getIntentById(surreal, intentId);
347→  if (!intent) {
348→    return {
349→      ok: false,
350→      error: {
351→        code: "INTENT_NOT_AUTHORIZED",
352→        message: `Intent ${intentId} not found`,
353→        httpStatus: 404,
354→      },
355→    };
356→  }
357→
358→  // Validate workspace scope: intent must belong to the session's workspace
359→  const intentWorkspaceId = intent.workspace.id as string;
360→  if (intentWorkspaceId !== workspaceId) {
361→    return {
362→      ok: false,
363→      error: {
364→        code: "WORKSPACE_MISMATCH",
365→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
366→        httpStatus: 403,
367→      },
368→    };
369→  }
370→
371→  const status = intent.status as IntentStatus;
372→  if (status !== "authorized") {
373→    return {
374→      ok: false,
375→      error: {
376→        code: "INTENT_NOT_AUTHORIZED",
377→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
378→        httpStatus: 403,
379→      },
380→    };
381→  }
382→
383→  return { ok: true, value: undefined as void };
384→}
385→
386→async function transitionIntentToExecuting(
387→  surreal: Surreal,
388→  intentId: string,
389→  sessionRecord: RecordId<"agent_session", string>,
390→): Promise<void> {
391→  await updateIntentStatus(surreal, intentId, "executing");
392→
393→  const intentRecord = new RecordId("intent", intentId);
394→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
395→  await surreal.query(
396→    "RELATE $intent->gates->$sess SET created_at = time::now();",
397→    { intent: intentRecord, sess: sessionRecord },
398→  );
399→
400→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
401→    intentId,
402→    sessionId: sessionRecord.id as string,
403→  });
404→}
405→
406→// ---------------------------------------------------------------------------
407→// Adapter-based session creation
408→// ---------------------------------------------------------------------------
409→
410→function slugFromTitle(title: string): string {
411→  return title
412→    .toLowerCase()
413→    .replace(/[^a-z0-9]+/g, "-")
414→    .replace(/^-|-$/g, "")
415→    .slice(0, 50);
416→}
417→
418→async function createSessionViaAdapter(
419→  input: CreateSessionInput,
420→  validation: import("./types").AssignmentValidation,
421→): Promise<OrchestratorSessionResult> {
422→  const adapter = input.adapter;
423→  const repoRoot = validation.repoPath;
424→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
425→
426→  // 1. Create worktree for isolated agent work
427→  const worktreeResult = await createWorktree(
428→    input.shellExec,
429→    repoRoot,
430→    taskSlug,
431→  );
432→
433→  if (!worktreeResult.ok) {
434→    return {
435→      ok: false,
436→      error: worktreeError(worktreeResult.error.message),
437→    };
438→  }
439→
440→  const { branchName, worktreePath } = worktreeResult.value;
441→
442→  // 2. Create agent_session record
443→  const { session_id: agentSessionId } = await input.createAgentSession({
444→    surreal: input.surreal,
445→    agent: "claude",
446→    workspaceRecord: validation.workspaceRecord,
447→    taskId: input.taskId,
448→  });
449→
450→  const streamId = generateStreamId(agentSessionId);
451→
452→  // 3. Create session via adapter — agent works in worktree, not main repo
453→  let handle: SessionHandle;
454→  try {
455→    handle = await adapter.createSession({
456→      agent: input.sandboxAgentType ?? "claude",
457→      cwd: worktreePath,
458→      ...(input.env ? { env: input.env } : {}),
459→    });
460→  } catch (err) {
461→    // Rollback: remove worktree and delete agent_session on adapter failure
462→    await removeWorktree(input.shellExec, repoRoot, branchName);
463→    const sessionRecord = new RecordId("agent_session", agentSessionId);
464→    await input.surreal.delete(sessionRecord);
465→    return {
466→      ok: false,
467→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
468→    };
469→  }
470→
471→  // 4. Update agent_session with sandbox + worktree fields
472→  const sessionRecord = new RecordId("agent_session", agentSessionId);
473→  await input.surreal.update(sessionRecord).merge({
474→    orchestrator_status: "spawning" as OrchestratorStatus,
475→    stream_id: streamId,
476→    session_type: "sandbox_agent",
477→    provider: "local",
478→    external_session_id: handle.id,
479→    worktree_branch: branchName,
480→    worktree_path: worktreePath,
481→  });
482→
483→  // 5. Transition intent to executing
484→  if (input.intentId) {
485→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
486→  }
487→
488→  return {
489→    ok: true,
490→    value: {
491→      agentSessionId,
492→      streamId,
493→      worktreeBranch: branchName,
494→      sessionHandle: handle,
495→    },
496→  };
497→}
498→
499→// ---------------------------------------------------------------------------
500→// getOrchestratorSessionStatus
501→// ---------------------------------------------------------------------------
502→
503→type GetStatusInput = {
504→  surreal: Surreal;
505→  sessionId: string;
506→};
507→
508→export async function getOrchestratorSessionStatus(
509→  input: GetStatusInput,
510→): Promise<SessionStatusResult> {
511→  const lookup = await lookupSession(input.surreal, input.sessionId);
512→  if (!lookup.ok) {
513→    return { ok: false, error: lookup.error };
514→  }
515→  const { session } = lookup;
516→
517→  return {
518→    ok: true,
519→    value: {
520→      orchestratorStatus: lookup.status,
521→      ...pickDefined({
522→        worktreeBranch: session.worktree_branch,
523→        worktreePath: session.worktree_path,
524→        startedAt: session.started_at,
525→        lastEventAt: session.last_event_at,
526→        error: session.error_message,
527→      }),
528→    },
529→  };
530→}
531→
532→// ---------------------------------------------------------------------------
533→// abortOrchestratorSession
534→// ---------------------------------------------------------------------------
535→
536→type AbortSessionInput = {
537→  surreal: Surreal;
538→  shellExec: ShellExec;
539→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
540→  sessionId: string;
541→  adapter: SandboxAgentAdapter;
542→  endAgentSession: (input: {
543→    surreal: Surreal;
544→    workspaceRecord: RecordId<"workspace", string>;
545→    sessionId: string;
546→    summary: string;
547→  }) => Promise<{ session_id: string; ended: boolean }>;
548→};
549→
550→export async function abortOrchestratorSession(
551→  input: AbortSessionInput,
552→): Promise<AbortSessionResult> {
553→  const lookup = await lookupSession(input.surreal, input.sessionId);
554→  if (!lookup.ok) {
555→    return { ok: false, error: lookup.error };
556→  }
557→  const { session, record: sessionRecord } = lookup;
558→
559→  // 1. Destroy the sandbox agent session
560→  if (session.external_session_id) {
561→    try {
562→      await input.adapter.destroySession(session.external_session_id);
563→    } catch (err) {
564→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
565→        sessionId: input.sessionId,
566→        externalSessionId: session.external_session_id,
567→        error: String(err),
568→      });
569→    }
570→  }
571→
572→  // 2. Update orchestrator_status to aborted
573→  await input.surreal.update(sessionRecord).merge({
574→    orchestrator_status: "aborted" as OrchestratorStatus,
575→  });
576→
577→  const workspaceRecord = requireWorkspace(session, input.sessionId);
578→
579→  // 3. Remove worktree if branch name exists
580→  if (session.worktree_branch) {
581→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
582→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
583→  }
584→
585→  // 4. Return task to ready
586→  if (session.task_id) {
587→    await input.surreal.update(session.task_id).merge({
588→      status: "ready",
589→      updated_at: new Date(),
590→    });
591→  }
592→
593→  // 5. End the agent session
594→  await input.endAgentSession({
595→    surreal: input.surreal,
596→    workspaceRecord,
597→    sessionId: input.sessionId,
598→    summary: "Session aborted",
599→  });
600→
601→  return {
602→    ok: true,
603→    value: {
604→      aborted: true,
605→      sessionId: input.sessionId,
606→    },
607→  };
608→}
609→
610→// ---------------------------------------------------------------------------
611→// acceptOrchestratorSession
612→// ---------------------------------------------------------------------------
613→
614→type AcceptSessionInput = {
615→  surreal: Surreal;
616→  shellExec: ShellExec;
617→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
618→  sessionId: string;
619→  summary: string;
620→  adapter: SandboxAgentAdapter;
621→  endAgentSession: (input: {
622→    surreal: Surreal;
623→    workspaceRecord: RecordId<"workspace", string>;
624→    sessionId: string;
625→    summary: string;
626→  }) => Promise<{ session_id: string; ended: boolean }>;
627→};
628→
629→export async function acceptOrchestratorSession(
630→  input: AcceptSessionInput,
631→): Promise<AcceptSessionResult> {
632→  const lookup = await lookupSession(input.surreal, input.sessionId);
633→  if (!lookup.ok) {
634→    return { ok: false, error: lookup.error };
635→  }
636→  const { session, record: sessionRecord, status } = lookup;
637→
638→  if (!ACCEPTABLE_STATUSES.has(status)) {
639→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
640→  }
641→
642→  const workspaceRecord = requireWorkspace(session, input.sessionId);
643→
644→  // 1. Destroy the sandbox agent session
645→  if (session.external_session_id) {
646→    try {
647→      await input.adapter.destroySession(session.external_session_id);
648→    } catch (err) {
649→      log.warn("orchestrator.accept", "Failed to destroy sandbox session", {
650→        sessionId: input.sessionId,
651→        externalSessionId: session.external_session_id,
652→        error: String(err),
653→      });
654→    }
655→  }
656→
657→  // 2. Update orchestrator_status to completed
658→  await input.surreal.update(sessionRecord).merge({
659→    orchestrator_status: "completed" as OrchestratorStatus,
660→  });
661→
662→  // 3. Remove worktree (branch is preserved for merge/review)
663→  if (session.worktree_branch) {
664→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
665→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
666→  }
667→
668→  // 4. End the agent session
669→  await input.endAgentSession({
670→    surreal: input.surreal,
671→    workspaceRecord,
672→    sessionId: input.sessionId,
673→    summary: input.summary,
674→  });
675→
676→  return {
677→    ok: true,
678→    value: {
679→      accepted: true,
680→      sessionId: input.sessionId,
681→    },
682→  };
683→}
684→
685→// ---------------------------------------------------------------------------
686→// State guard helpers
687→// ---------------------------------------------------------------------------
688→
689→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
690→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
691→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
692→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
693→
694→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
695→  return {
696→    code: "SESSION_ERROR",
697→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
698→    httpStatus: 409,
699→  };
700→}
701→
702→function sessionAborted(sessionId: string): SessionError {
703→  return {
704→    code: "SESSION_ERROR",
705→    message: `Session ${sessionId} has been aborted`,
706→    httpStatus: 409,
707→  };
708→}
709→
710→// ---------------------------------------------------------------------------
711→// getOrchestratorReview
712→// ---------------------------------------------------------------------------
713→
714→type GetReviewInput = {
715→  surreal: Surreal;
716→  sessionId: string;
717→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
718→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
719→  getTaskTitle: (taskId: string) => Promise<string>;
720→};
721→
722→export async function getOrchestratorReview(
723→  input: GetReviewInput,
724→): Promise<ReviewResult> {
725→  const lookup = await lookupSession(input.surreal, input.sessionId);
726→  if (!lookup.ok) {
727→    return { ok: false, error: lookup.error };
728→  }
729→  const { session, status } = lookup;
730→
731→  if (status === "aborted") {
732→    return { ok: false, error: sessionAborted(input.sessionId) };
733→  }
734→
735→  if (!REVIEWABLE_STATUSES.has(status)) {
736→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
737→  }
738→
739→  // Get diff from the branch
740→  const branchName = session.worktree_branch ?? "";
741→  const workspaceRecord = requireWorkspace(session, input.sessionId);
742→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
743→  const diffResult = await input.getDiff(repoRoot, branchName);
744→
745→  const diff = diffResult.ok
746→    ? diffResult.value
747→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
748→
749→  // Get task title
750→  const taskId = session.task_id ? session.task_id.id : "";
751→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
752→
753→  return {
754→    ok: true,
755→    value: {
756→      taskTitle,
757→      diff,
758→      session: {
759→        orchestratorStatus: status,
760→        ...pickDefined({
761→          worktreeBranch: session.worktree_branch,
762→          startedAt: session.started_at,
763→          lastEventAt: session.last_event_at,
764→        }),
765→      },
766→    },
767→  };
768→}
769→
770→// ---------------------------------------------------------------------------
771→// rejectOrchestratorSession
772→// ---------------------------------------------------------------------------
773→
774→type RejectSessionInput = {
775→  surreal: Surreal;
776→  sessionId: string;
777→  feedback: string;
778→};
779→
780→export async function rejectOrchestratorSession(
781→  input: RejectSessionInput,
782→): Promise<RejectSessionResult> {
783→  const lookup = await lookupSession(input.surreal, input.sessionId);
784→  if (!lookup.ok) {
785→    return { ok: false, error: lookup.error };
786→  }
787→  const { session, record: sessionRecord, status } = lookup;
788→
789→  if (!REJECTABLE_STATUSES.has(status)) {
790→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
791→  }
792→
793→  // 1. Update session status to active (agent resumes work)
794→  await input.surreal.update(sessionRecord).merge({
795→    orchestrator_status: "active" as OrchestratorStatus,
796→    last_feedback: input.feedback,
797→  });
798→
799→  // 2. Return task to in_progress
800→  if (session.task_id) {
801→    await input.surreal.update(session.task_id).merge({
802→      status: "in_progress",
803→      updated_at: new Date(),
804→    });
805→  }
806→
807→  return {
808→    ok: true,
809→    value: {
810→      rejected: true,
811→      continuing: true,
812→    },
813→  };
814→}
815→
816→// ---------------------------------------------------------------------------
817→// sendSessionPrompt
818→// ---------------------------------------------------------------------------
819→
820→type SendPromptInput = {
821→  surreal: Surreal;
822→  sessionId: string;
823→  text: string;
824→  adapter: SandboxAgentAdapter;
825→};
826→
827→export async function sendSessionPrompt(
828→  input: SendPromptInput,
829→): Promise<PromptSessionResult> {
830→  const lookup = await lookupSession(input.surreal, input.sessionId);
831→  if (!lookup.ok) {
832→    return { ok: false, error: lookup.error };
833→  }
834→  const { session, status } = lookup;
835→
836→  if (!PROMPTABLE_STATUSES.has(status)) {
837→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
838→    if (TERMINAL_STATUSES.has(status)) {
839→      return { ok: false, error: sessionNotFound(input.sessionId) };
840→    }
841→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
842→  }
843→
844→  if (!session.external_session_id) {
845→    return {
846→      ok: false,
847→      error: {
848→        code: "SESSION_ERROR",
849→        message: `Session ${input.sessionId} has no external_session_id — cannot deliver prompt`,
850→        httpStatus: 500,
851→      },
852→    };
853→  }
854→
855→  try {
856→    const handle = await input.adapter.resumeSession(session.external_session_id);
857→    await handle.prompt([{ type: "text", text: input.text }]);
858→    return { ok: true, value: { delivered: true } };
859→  } catch (err) {
860→    return {
861→      ok: false,
862→      error: {
863→        code: "SESSION_ERROR",
864→        message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
865→        httpStatus: 500,
866→      },
867→    };
868→  }
869→}
870→

